class Solution:
    def isSelfCrossing(self, distance: List[int]) -> bool:
        d = distance
        for i in range(3, len(d)):
            if d[i] >= d[i-2] and d[i-1] <= d[i-3]:
                return True
            if i >= 4 and d[i-1] == d[i-3] and d[i] + d[i-4] >= d[i-2]:
                return True
            if i >= 5 and d[i-2] >= d[i-4] and d[i-3] <= d[i-1] and d[i] + d[i-4] >= d[i-2] and d[i-1] - d[i-3] < d[i-5]:
                return True
        return False

